mapper.select:
SELECT d.order_no AS orderNo, COUNT(1) AS totalItemCount, SUM(CASE WHEN r.id IS NULL THEN 1 ELSE 0 END) AS pendingReviewCount FROM t_order_detail_sku d LEFT JOIN t_order_sku_review r ON r.order_no = d.order_no AND r.order_detail_sku_id = d.id AND r.del_flag = 0 WHERE d.del_flag = 0 AND d.order_no IN
#{orderNo}
GROUP BY d.order_no
